"use client";

import { useState } from "react";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import { z } from "zod";
import { DataTable, Column } from "@/components/tables/data-table";
import {
  useCategories,
  useCreateCategory,
  useUpdateCategory,
  useToggleCategoryActive,
  useDeleteCategory,
} from "@/hooks/use-categories";
import type { Category } from "@/types";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Switch } from "@/components/ui/switch";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import {
  Sheet,
  SheetContent,
  SheetHeader,
  SheetTitle,
  SheetDescription,
} from "@/components/ui/sheet";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from "@/components/ui/alert-dialog";
import { MoreHorizontal, Plus, Pencil, Trash2, FolderOpen } from "lucide-react";
import { formatDate } from "@/lib/utils";

const categorySchema = z.object({
  name: z.string().min(1, "Name is required"),
  description: z.string().optional(),
  icon: z.string().optional(),
  color: z.string().optional(),
  sortOrder: z.coerce.number().default(0),
});

type CategoryForm = z.infer<typeof categorySchema>;

export default function CategoriesPage() {
  const [drawerOpen, setDrawerOpen] = useState(false);
  const [editTarget, setEditTarget] = useState<Category | null>(null);
  const [deleteTarget, setDeleteTarget] = useState<Category | null>(null);

  const { data, isLoading } = useCategories();
  const create = useCreateCategory();
  const update = useUpdateCategory();
  const toggleActive = useToggleCategoryActive();
  const deleteCategory = useDeleteCategory();

  const {
    register,
    handleSubmit,
    reset,
    formState: { errors },
  } = useForm<CategoryForm>({
    resolver: zodResolver(categorySchema),
  });

  const openCreate = () => {
    setEditTarget(null);
    reset({ name: "", description: "", icon: "", color: "", sortOrder: 0 });
    setDrawerOpen(true);
  };

  const openEdit = (cat: Category) => {
    setEditTarget(cat);
    reset({
      name: cat.name,
      description: cat.description ?? "",
      icon: cat.icon ?? "",
      color: cat.color ?? "",
      sortOrder: cat.sortOrder,
    });
    setDrawerOpen(true);
  };

  const onSubmit = (values: CategoryForm) => {
    if (editTarget) {
      update.mutate({ id: editTarget.id, ...values });
    } else {
      create.mutate(values);
    }
    setDrawerOpen(false);
    reset();
  };

  const columns: Column<Category>[] = [
    {
      key: "name",
      header: "Name",
      cell: (cat) => (
        <div className="flex items-center gap-3">
          {cat.color && (
            <div
              className="w-3 h-3 rounded-full flex-shrink-0"
              style={{ backgroundColor: cat.color }}
            />
          )}
          <div>
            <p className="font-medium text-sm">{cat.name}</p>
            {cat.icon && (
              <p className="text-xs text-muted-foreground">{cat.icon}</p>
            )}
          </div>
        </div>
      ),
    },
    {
      key: "description",
      header: "Description",
      cell: (cat) => (
        <span className="text-sm text-muted-foreground truncate max-w-[200px] block">
          {cat.description ?? "—"}
        </span>
      ),
    },
    {
      key: "sortOrder",
      header: "Order",
      cell: (cat) => <span className="text-sm">{cat.sortOrder}</span>,
    },
    {
      key: "isActive",
      header: "Active",
      cell: (cat) => (
        <Switch
          checked={cat.isActive}
          onCheckedChange={() => toggleActive.mutate(cat.id)}
        />
      ),
    },
    {
      key: "isPro",
      header: "Pro",
      cell: (cat) => (
        <Badge variant={cat.isPro ? "default" : "outline"}>
          {cat.isPro ? "Pro" : "Free"}
        </Badge>
      ),
    },
    {
      key: "createdAt",
      header: "Created",
      cell: (cat) => (
        <span className="text-sm text-muted-foreground">
          {formatDate(cat.createdAt)}
        </span>
      ),
    },
    {
      key: "actions",
      header: "",
      cell: (cat) => (
        <DropdownMenu>
          <DropdownMenuTrigger asChild>
            <Button variant="ghost" size="icon" className="h-8 w-8">
              <MoreHorizontal className="h-4 w-4" />
            </Button>
          </DropdownMenuTrigger>
          <DropdownMenuContent align="end">
            <DropdownMenuItem onClick={() => openEdit(cat)}>
              <Pencil className="mr-2 h-4 w-4" />
              Edit
            </DropdownMenuItem>
            <DropdownMenuSeparator />
            <DropdownMenuItem
              className="text-red-600 focus:text-red-600"
              onClick={() => setDeleteTarget(cat)}
            >
              <Trash2 className="mr-2 h-4 w-4" />
              Delete
            </DropdownMenuItem>
          </DropdownMenuContent>
        </DropdownMenu>
      ),
    },
  ];

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between flex-wrap gap-3">
        <div className="flex items-center gap-3">
          <div className="p-2 rounded-lg bg-orange-100">
            <FolderOpen className="h-5 w-5 text-orange-600" />
          </div>
          <div>
            <h1 className="text-2xl font-bold">Categories</h1>
            <p className="text-muted-foreground text-sm">Manage place categories</p>
          </div>
        </div>
        <Button onClick={openCreate}>
          <Plus className="mr-2 h-4 w-4" />
          New Category
        </Button>
      </div>

      <DataTable
        columns={columns}
        data={(data?.data ?? []) as Category[]}
        isLoading={isLoading}
        searchKey="name"
        searchPlaceholder="Search categories..."
      />

      {/* Create/Edit Drawer */}
      <Sheet open={drawerOpen} onOpenChange={setDrawerOpen}>
        <SheetContent className="sm:max-w-md">
          <SheetHeader>
            <SheetTitle>{editTarget ? "Edit Category" : "New Category"}</SheetTitle>
            <SheetDescription>
              {editTarget
                ? "Update category details below."
                : "Fill in the details to create a new category."}
            </SheetDescription>
          </SheetHeader>

          <form onSubmit={handleSubmit(onSubmit)} className="mt-6 space-y-4">
            <div className="space-y-2">
              <Label htmlFor="name">Name *</Label>
              <Input id="name" {...register("name")} placeholder="Category name" />
              {errors.name && (
                <p className="text-red-500 text-xs">{errors.name.message}</p>
              )}
            </div>
            <div className="space-y-2">
              <Label htmlFor="description">Description</Label>
              <Textarea
                id="description"
                {...register("description")}
                placeholder="Optional description"
                rows={3}
              />
            </div>
            <div className="grid grid-cols-2 gap-3">
              <div className="space-y-2">
                <Label htmlFor="icon">Icon</Label>
                <Input id="icon" {...register("icon")} placeholder="e.g. 🏨" />
              </div>
              <div className="space-y-2">
                <Label htmlFor="color">Color</Label>
                <Input id="color" {...register("color")} placeholder="#3b82f6" />
              </div>
            </div>
            <div className="space-y-2">
              <Label htmlFor="sortOrder">Sort Order</Label>
              <Input id="sortOrder" type="number" {...register("sortOrder")} placeholder="0" />
            </div>
            <div className="flex gap-2 pt-4">
              <Button type="button" variant="outline" className="flex-1" onClick={() => setDrawerOpen(false)}>
                Cancel
              </Button>
              <Button type="submit" className="flex-1" disabled={create.isPending || update.isPending}>
                {editTarget ? "Save Changes" : "Create Category"}
              </Button>
            </div>
          </form>
        </SheetContent>
      </Sheet>

      {/* Delete Confirm */}
      <AlertDialog open={!!deleteTarget} onOpenChange={() => setDeleteTarget(null)}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>Delete Category</AlertDialogTitle>
            <AlertDialogDescription>
              Are you sure you want to delete &quot;{deleteTarget?.name}&quot;? This action cannot be undone.
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel>Cancel</AlertDialogCancel>
            <AlertDialogAction
              className="bg-red-600 hover:bg-red-700"
              onClick={() => {
                if (deleteTarget) deleteCategory.mutate(deleteTarget.id);
                setDeleteTarget(null);
              }}
            >
              Delete
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </div>
  );
}
